describe("statuspage.app.nz landing page",function(){it("renders the core brand and pricing",function(){expect(document.title).toContain("statuspage.app.nz"),expect(document.querySelector(".brand strong").textContent).toContain("statuspage.app.nz"),expect(document.body.textContent).toContain("$190/year"),expect(document.querySelector("#billing-form input[name='plan'][value='annual']").checked).toBeTrue(),expect(document.querySelector("#billing-form input[name='plan'][value='monthly']")).not.toBeNull()}),it("renders the example status dashboard",function(){expect(document.querySelector(".dashboard")).not.toBeNull(),expect(document.body.textContent).toContain("All systems operational"),expect(document.querySelectorAll(".monitor-table .row").length).toBeGreaterThan(3)}),it("renders real Applied AI product links",function(){var t=document.querySelector("#customers");expect(t).not.toBeNull(),expect(t.textContent).toContain("Applied AI products"),expect(t.textContent).toContain("text-generator.io"),expect(t.textContent).toContain("netwrck.com"),expect(t.textContent).toContain("simplexgen.com"),expect(t.textContent).not.toContain("devmate.co.nz"),expect(t.textContent).not.toContain("Add your business")}),it("renders login and signup controls",function(){expect(document.querySelector("#auth-form")).not.toBeNull(),expect(document.querySelector("[data-mode='login']")).not.toBeNull(),expect(document.querySelector("[data-mode='forgot']")).not.toBeNull(),expect(document.querySelector("#signup-form")).not.toBeNull(),expect(document.querySelector("#billing-dialog")).not.toBeNull()}),it("switches the account panel to login mode",function(){document.querySelector("[data-mode='login']").click(),expect(document.querySelector(".company-field").hidden).toBeTrue(),expect(document.querySelector("#auth-form button").textContent).toContain("Login")}),it("opens billing from the signed-in account state",function(){document.querySelector(".account-state").hidden=!1,document.querySelector("#auth-form").hidden=!0,document.querySelector("#account-name").textContent="Test Co",document.querySelector("#account-email").textContent="test@example.com",document.querySelector("#open-billing-button").click(),expect(document.querySelector("#billing-dialog").open).toBeTrue(),document.querySelector("#billing-dialog").close(),expect(document.querySelector("#logout-button")).toBeNull()}),it("has a full footer with product and company links",function(){var t=document.querySelector(".site-footer");expect(t).not.toBeNull(),expect(t.textContent).toContain("Product"),expect(t.textContent).toContain("Company"),expect(t.textContent).toContain("app.nz"),expect(t.textContent).toContain("lee101/gobed"),expect(t.textContent).not.toContain("hello@appliedai.nz"),expect(t.querySelectorAll("a").length).toBeGreaterThan(7)}),it("keeps the trust section customer-facing",function(){var t=document.querySelector("#trust");expect(t).not.toBeNull(),expect(t.textContent).toContain("Give customers confidence"),expect(t.textContent).not.toContain("Postgres"),expect(t.textContent).not.toContain("Stripe Checkout"),expect(t.textContent).not.toContain("signed secure session cookies")}),it("serves the health endpoint",function(t){fetch("/health").then(function(e){return expect(e.status).toBe(200),e.json()}).then(function(e){expect(e.ok).toBeTrue(),t()}).catch(t.fail)}),it("returns a controlled auth state from /api/me",function(t){fetch("/api/me").then(function(e){return expect([200,401,503]).toContain(e.status),e.json()}).then(function(e){expect(e.user||e.error).toBeDefined(),t()}).catch(t.fail)}),it("searches the customer directory API",function(t){fetch("/api/customers?q=gobed").then(function(e){return expect(e.status).toBe(200),e.json()}).then(function(e){expect(e.customers.length).toBeGreaterThan(0),expect(e.customers[0].domain).toContain("gobed"),t()}).catch(t.fail)}),it("exposes the status page API with controlled auth",function(t){fetch("/api/v1/status-pages").then(function(e){return expect([200,401,503]).toContain(e.status),e.json()}).then(function(e){expect(e.status_pages||e.error).toBeDefined(),t()}).catch(t.fail)})});
